CREATE TABLE IF NOT EXISTS admin_departments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, parent_department_id UUID REFERENCES admin_departments(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, slug VARCHAR(120) NOT NULL, business_unit VARCHAR(180), settings JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ, CONSTRAINT uq_admin_department_org_slug UNIQUE (organization_id, slug));
CREATE TABLE IF NOT EXISTS user_groups (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, slug VARCHAR(120) NOT NULL, description TEXT, attributes JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ, CONSTRAINT uq_user_group_org_slug UNIQUE (organization_id, slug));
CREATE TABLE IF NOT EXISTS user_group_members (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, group_id UUID NOT NULL REFERENCES user_groups(id) ON DELETE CASCADE, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, role VARCHAR(80) NOT NULL DEFAULT 'member', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS custom_roles (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(160) NOT NULL, slug VARCHAR(100) NOT NULL, description TEXT, permissions JSONB NOT NULL DEFAULT '[]'::jsonb, constraints JSONB NOT NULL DEFAULT '{}'::jsonb, status VARCHAR(40) NOT NULL DEFAULT 'active', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ, CONSTRAINT uq_custom_role_org_slug UNIQUE (organization_id, slug));
CREATE TABLE IF NOT EXISTS governance_policies (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, inherited_from_id UUID REFERENCES governance_policies(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, policy_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'active', enforcement_mode VARCHAR(40) NOT NULL DEFAULT 'monitor', scope JSONB NOT NULL DEFAULT '{}'::jsonb, rules JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS abac_policies (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, effect VARCHAR(40) NOT NULL DEFAULT 'allow', resource_type VARCHAR(80) NOT NULL, action VARCHAR(120) NOT NULL, conditions JSONB NOT NULL DEFAULT '{}'::jsonb, priority INTEGER NOT NULL DEFAULT 100, status VARCHAR(40) NOT NULL DEFAULT 'active', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS sso_connections (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, provider VARCHAR(80) NOT NULL, protocol VARCHAR(40) NOT NULL DEFAULT 'oidc', name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'disabled', domain VARCHAR(180), issuer_url TEXT, metadata_url TEXT, secret_ref TEXT, config JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS mfa_factors (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, factor_type VARCHAR(60) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'enrolled', secret_ref TEXT, last_verified_at TIMESTAMPTZ, metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS trusted_devices (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, device_fingerprint VARCHAR(160) NOT NULL, device_type VARCHAR(80), status VARCHAR(40) NOT NULL DEFAULT 'trusted', last_seen_at TIMESTAMPTZ, metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS secret_records (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, secret_type VARCHAR(80) NOT NULL, provider VARCHAR(80) NOT NULL DEFAULT 'internal', secret_ref TEXT NOT NULL, rotation_policy JSONB NOT NULL DEFAULT '{}'::jsonb, current_version INTEGER NOT NULL DEFAULT 1, status VARCHAR(40) NOT NULL DEFAULT 'active', last_rotated_at TIMESTAMPTZ, expires_at TIMESTAMPTZ, metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS secret_versions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, secret_record_id UUID NOT NULL REFERENCES secret_records(id) ON DELETE CASCADE, version INTEGER NOT NULL, secret_ref TEXT NOT NULL, fingerprint VARCHAR(160), status VARCHAR(40) NOT NULL DEFAULT 'active', metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS compliance_frameworks (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, framework VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'not_started', readiness_score NUMERIC(5,2) NOT NULL DEFAULT 0, controls JSONB NOT NULL DEFAULT '{}'::jsonb, evidence_summary JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS compliance_evidence (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, framework_id UUID REFERENCES compliance_frameworks(id) ON DELETE SET NULL, file_id UUID REFERENCES files(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, control_id VARCHAR(120) NOT NULL, evidence_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'collected', metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS data_governance_policies (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, policy_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'active', data_classification VARCHAR(80), retention_days INTEGER, residency_region VARCHAR(80), legal_hold JSONB NOT NULL DEFAULT '{}'::jsonb, rules JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS encryption_key_records (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, key_alias VARCHAR(180) NOT NULL, key_type VARCHAR(80) NOT NULL DEFAULT 'platform', provider VARCHAR(80) NOT NULL DEFAULT 'internal', key_ref TEXT NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'active', rotation_policy JSONB NOT NULL DEFAULT '{}'::jsonb, last_rotated_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS security_risk_events (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, user_id UUID REFERENCES users(id) ON DELETE SET NULL, event_type VARCHAR(120) NOT NULL, risk_level VARCHAR(40) NOT NULL DEFAULT 'low', risk_score NUMERIC(5,2) NOT NULL DEFAULT 0, status VARCHAR(40) NOT NULL DEFAULT 'open', signal_payload JSONB NOT NULL DEFAULT '{}'::jsonb, mitigation_state JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS security_health_scores (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, score NUMERIC(5,2) NOT NULL DEFAULT 0, grade VARCHAR(8) NOT NULL DEFAULT 'C', factors JSONB NOT NULL DEFAULT '{}'::jsonb, recommendations JSONB NOT NULL DEFAULT '[]'::jsonb, captured_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS governance_graph_snapshots (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID REFERENCES workspaces(id) ON DELETE CASCADE, snapshot_type VARCHAR(80) NOT NULL DEFAULT 'organization', node_count INTEGER NOT NULL DEFAULT 0, edge_count INTEGER NOT NULL DEFAULT 0, graph_payload JSONB NOT NULL DEFAULT '{}'::jsonb, captured_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS ix_governance_policies_workspace_type ON governance_policies(workspace_id, policy_type, status);
CREATE INDEX IF NOT EXISTS ix_abac_policies_resource_action ON abac_policies(resource_type, action, status, priority);
CREATE INDEX IF NOT EXISTS ix_sso_connections_org_provider ON sso_connections(organization_id, provider, status);
CREATE INDEX IF NOT EXISTS ix_secret_records_workspace_type ON secret_records(workspace_id, secret_type, status);
CREATE INDEX IF NOT EXISTS ix_compliance_frameworks_org_status ON compliance_frameworks(organization_id, framework, status);
CREATE INDEX IF NOT EXISTS ix_security_risk_events_workspace_level ON security_risk_events(workspace_id, risk_level, status);
CREATE INDEX IF NOT EXISTS ix_security_health_scores_org_captured ON security_health_scores(organization_id, captured_at);